import re
import json

# This script demonstrates a minimal, self-contained experiment inspired by the
# execution-based testing methodology from the bpmn-sol-llm-benchmark repository.
# Instead of compiling and running Solidity smart contracts, this script "executes"
# or verifies steps in a Chain-of-Thought (CoT) reasoning path against ground-truth
# scene data.

# --- Sample Data (Simulating VQASynth output) ---
# This would typically be loaded from a dataset generated by the main VQASynth pipeline.
# It contains the ground truth data against which the reasoning is verified.
SAMPLE_VQA_DATA = {
    "question": "Is the green chair to the left of the wooden table?",
    "reasoning_chain": [
        "1. Identify the 'green chair'.",
        "2. Identify the 'wooden table'.",
        "3. The chair is to the left of the table.",
        "4. The chair's x-coordinate (1.2) is less than the table's x-coordinate (3.5), so it is to the left."
    ],
    "answer": "Yes, the green chair is to the left of the wooden table.",
    "scene_ground_truth": {
        "objects": [
            {"name": "green chair", "coordinates": {"x": 1.2, "y": 2.0, "z": 0.5}},
            {"name": "wooden table", "coordinates": {"x": 3.5, "y": 2.1, "z": 0.0}},
            {"name": "red lamp", "coordinates": {"x": 3.6, "y": 2.1, "z": 1.5}}
        ]
    }
}

class ReasoningVerifier:
    """
    A verifier that parses natural language reasoning steps and checks them
    against programmatic ground truth data.
    """
    def __init__(self, ground_truth):
        self.ground_truth = ground_truth
        self.object_map = {obj['name']: obj['coordinates'] for obj in ground_truth.get('objects', [])}

    def verify_step(self, step_text):
        """
        Parses and verifies a single reasoning step.
        This is a simplified parser for demonstration purposes.
        """
        # Example rule: "The [obj1] is to the [relation] of the [obj2]."
        match = re.search(r"the (.*?) is to the (left|right) of the (.*?)\.", step_text, re.IGNORECASE)
        if match:
            obj1_name, relation, obj2_name = match.groups()
            return self._verify_spatial_relation(obj1_name.strip(), relation.strip(), obj2_name.strip())

        # Example rule: Check coordinate comparison
        # "The chair's x-coordinate (1.2) is less than the table's x-coordinate (3.5)"
        match = re.search(r"coordinate \(([\d\.]+)\) is (less|greater) than .*? coordinate \(([\d\.]+)\)", step_text, re.IGNORECASE)
        if match:
            val1, comparison, val2 = match.groups()
            val1, val2 = float(val1), float(val2)
            if comparison == "less" and val1 < val2:
                return True, f"Expression '{val1} < {val2}' is true."
            if comparison == "greater" and val1 > val2:
                return True, f"Expression '{val1} > {val2}' is true."
            return False, f"Expression '{val1} {comparison} {val2}' is false."


        return None, "Step format not recognized by verifier."

    def _verify_spatial_relation(self, obj1_name, relation, obj2_name):
        """Checks a spatial relationship like 'left of' or 'right of'."""
        if obj1_name not in self.object_map or obj2_name not in self.object_map:
            return False, f"Could not find one or both objects: '{obj1_name}', '{obj2_name}'"

        obj1_coords = self.object_map[obj1_name]
        obj2_coords = self.object_map[obj2_name]

        is_correct = False
        if relation == 'left':
            is_correct = obj1_coords['x'] < obj2_coords['x']
            eval_str = f"'{obj1_name}'.x ({obj1_coords['x']}) < '{obj2_name}'.x ({obj2_coords['x']})"
        elif relation == 'right':
            is_correct = obj1_coords['x'] > obj2_coords['x']
            eval_str = f"'{obj1_name}'.x ({obj1_coords['x']}) > '{obj2_name}'.x ({obj2_coords['x']})"
        else:
            return False, f"Unknown relation: {relation}"

        if is_correct:
            return True, f"PASSED: {eval_str}"
        else:
            return False, f"FAILED: {eval_str}"

    def run_verification(self, reasoning_chain):
        """Runs verification for a full chain of reasoning."""
        print("--- Starting Reasoning Verification ---")
        results = []
        for i, step in enumerate(reasoning_chain):
            is_valid, message = self.verify_step(step)
            result = {
                "step": i + 1,
                "text": step,
                "verified": is_valid,
                "message": message
            }
            results.append(result)
            status = "SKIPPED"
            if is_valid is True:
                status = "PASSED"
            elif is_valid is False:
                status = "FAILED"
            print(f"Step {i+1}: {status} | {message}")

        print("--- Verification Complete ---")
        return results

def main():
    """Main function to run the experiment."""
    print("Initializing experiment: Reasoning Execution Verifier")
    print("This experiment tests the feasibility of programmatically verifying VLM reasoning steps.")
    print(f"Source VQA Sample:\n{json.dumps(SAMPLE_VQA_DATA, indent=2)}\n")

    verifier = ReasoningVerifier(SAMPLE_VQA_DATA['scene_ground_truth'])
    verification_results = verifier.run_verification(SAMPLE_VQA_DATA['reasoning_chain'])

    # Calculate success rate
    passed_steps = sum(1 for r in verification_results if r['verified'] is True)
    failed_steps = sum(1 for r in verification_results if r['verified'] is False)
    total_verifiable = passed_steps + failed_steps
    
    print("\n--- Summary ---")
    if total_verifiable > 0:
        correctness_score = (passed_steps / total_verifiable) * 100
        print(f"Verifiable Steps: {total_verifiable}")
        print(f"Passed: {passed_steps}")
        print(f"Failed: {failed_steps}")
        print(f"Reasoning Correctness Score: {correctness_score:.2f}%")
    else:
        print("No verifiable steps were found in the reasoning chain.")

if __name__ == "__main__":
    main()
